class CoalescingAnalyzer:
    """Analyze GPU memory coalescing for warp access patterns."""

    def __init__(self, cache_line_size=128):
        self.cache_line_size = cache_line_size
        self.warp_size = 32

    def count_transactions(self, addresses):
        """
        Count 128-byte transactions needed for 32 thread addresses.
        """
        cache_lines = set()
        for addr in addresses:
            line = addr // self.cache_line_size
            cache_lines.add(line)
        return len(cache_lines)

    def analyze_pattern(self, addresses, element_size=4):
        """
        Analyze an access pattern's efficiency.
        """
        transactions = self.count_transactions(addresses)
        bytes_transferred = transactions * self.cache_line_size
        bytes_useful = self.warp_size * element_size
        utilization = bytes_useful / bytes_transferred if bytes_transferred > 0 else 0.0

        if transactions == 1:
            pattern = 'perfect'
        elif transactions <= 2:
            pattern = 'good'
        elif transactions <= 8:
            pattern = 'poor'
        else:
            pattern = 'terrible'

        return {
            'transactions': transactions,
            'bytes_transferred': bytes_transferred,
            'bytes_useful': bytes_useful,
            'utilization': utilization,
            'pattern': pattern,
        }

    def generate_stride_pattern(self, base, stride, element_size=4):
        """
        Generate addresses for stride access.
        """
        return [base + i * stride * element_size for i in range(self.warp_size)]

    def compare_patterns(self, patterns_dict):
        """
        Compare multiple access patterns, sorted by transaction count.
        """
        results = []
        for name, addresses in patterns_dict.items():
            analysis = self.analyze_pattern(addresses)
            analysis['name'] = name
            results.append(analysis)
        return sorted(results, key=lambda x: x['transactions'])
